'use strict';

// 内置 RFC 4122 UUID v4 生成器，替代 uuid@8 依赖
//
// 实现严格遵循 RFC 4122：
//   - 16 字节强随机
//   - bytes[6] 高 4 位 = 0100（version 4）
//   - bytes[8] 高 2 位 = 10xx（variant 10xx）
//
// 输出格式（小写）：xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx，y ∈ {8,9,a,b}
//
// 行为与 uuid@8.3.2 的 v4()（无参调用）等价。仅支持无参形式；
// 如需 buf/offset 写入数组的高级用法，请使用上游 uuid 包。

var crypto = require('crypto');

function uuidV4() {
  var bytes = crypto.randomBytes(16);
  // RFC 4122 §4.4: 设置 version (4) 和 variant 位
  bytes[6] = (bytes[6] & 0x0f) | 0x40;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;

  var hex = bytes.toString('hex');
  return (
    hex.substring(0, 8) + '-' +
    hex.substring(8, 12) + '-' +
    hex.substring(12, 16) + '-' +
    hex.substring(16, 20) + '-' +
    hex.substring(20, 32)
  );
}

module.exports = uuidV4;
